import"./modulepreload-polyfill-B5Qt9EMX.js";const m="https://agenda-1-zomu.onrender.com";async function l(t,n,o){const e=await fetch(`${m}/auth/register`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:n,password:o})});if(!e.ok){const r=await e.json();throw new Error(r.detail||"Error al crear la cuenta")}return e.json()}document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("registerContainer");setTimeout(()=>{t.classList.remove("initial-hidden"),t.classList.add("show-form")},10)});const c=document.getElementById("registerForm"),u=document.getElementById("nombre"),g=document.getElementById("email"),E=document.getElementById("password"),f=document.getElementById("confirmPassword"),a=document.getElementById("error"),i=document.getElementById("buttonText");c.addEventListener("submit",async t=>{t.preventDefault(),y();const n=u.value.trim(),o=g.value.trim(),e=E.value.trim(),r=f.value.trim();if(!n||!o||!e||!r){s("Todos los campos son obligatorios.");return}if(e.length<6){s("La contraseña debe tener al menos 6 caracteres.");return}if(e!==r){s("Las contraseñas no coinciden.");return}i.textContent="Creando cuenta...",c.querySelector("button").disabled=!0;try{await l(n,o,e),window.location.href="/index.html"}catch(d){s(d.message),i.textContent="REGISTRARSE",c.querySelector("button").disabled=!1}});function s(t){a.textContent=t,a.classList.remove("hidden")}function y(){a.textContent="",a.classList.add("hidden")}
